      function buildTaskRunStatusIndicatorItem(taskRunState) {
        const normalizedTaskId = typeof taskRunState?.taskId === "string" ? taskRunState.taskId.trim() : "";
        if (!normalizedTaskId) {
          return null;
        }

        const ticketPrefix = typeof taskRunState?.ticketNumber === "string" && taskRunState.ticketNumber.trim()
          ? taskRunState.ticketNumber.trim() + " "
          : "";
        const taskLabel = ticketPrefix + (typeof taskRunState?.title === "string" && taskRunState.title.trim()
          ? taskRunState.title.trim()
          : "Untitled Task");
        const phase = typeof taskRunState?.phase === "string" ? taskRunState.phase.trim().toLowerCase() : "";

        if (phase === "starting") {
          return {
            id: "task-run:" + normalizedTaskId,
            title: "Task scheduled",
            copy: taskLabel + " will begin shortly.",
          };
        }

        if (phase === "running") {
          return {
            id: "task-run:" + normalizedTaskId,
            title: "Task running",
            copy: taskLabel,
          };
        }

        if (phase === "finished") {
          return {
            id: "task-run:" + normalizedTaskId,
            title: "Task finished",
            copy: taskLabel,
          };
        }

        if (phase === "failed") {
          return {
            id: "task-run:" + normalizedTaskId,
            title: "Task failed to start",
            copy: typeof taskRunState?.error === "string" && taskRunState.error.trim()
              ? taskRunState.error.trim()
              : taskLabel,
          };
        }

        if (phase === "cancelled") {
          return {
            id: "task-run:" + normalizedTaskId,
            title: "Task cancelled",
            copy: taskLabel,
          };
        }

        return null;
      }

      function buildMissionControlStatusIndicatorItem(runState) {
        const normalizedProjectId = typeof runState?.projectId === "string" ? runState.projectId.trim() : "";
        if (!normalizedProjectId) {
          return null;
        }

        const projectName = typeof runState?.projectName === "string" && runState.projectName.trim()
          ? runState.projectName.trim()
          : "Project";
        const missionLabel = projectName + " Mission Control";
        const phase = typeof runState?.phase === "string" ? runState.phase.trim().toLowerCase() : "";

        if (phase === "starting") {
          return {
            id: "mission-control:" + normalizedProjectId,
            title: "Mission Control scheduled",
            copy: missionLabel + " will begin shortly.",
          };
        }

        if (phase === "running") {
          return {
            id: "mission-control:" + normalizedProjectId,
            title: "Mission Control running",
            copy: missionLabel,
          };
        }

        if (phase === "finished") {
          return {
            id: "mission-control:" + normalizedProjectId,
            title: "Mission Control finished",
            copy: missionLabel,
          };
        }

        if (phase === "failed") {
          return {
            id: "mission-control:" + normalizedProjectId,
            title: "Mission Control failed to start",
            copy: typeof runState?.error === "string" && runState.error.trim()
              ? runState.error.trim()
              : missionLabel,
          };
        }

        if (phase === "cancelled") {
          return {
            id: "mission-control:" + normalizedProjectId,
            title: "Mission Control cancelled",
            copy: missionLabel,
          };
        }

        return null;
      }

      function getAccountInitials(value) {
        const normalized = String(value || "").trim();
        if (!normalized) {
          return "CA";
        }

        const emailPrefix = normalized.includes("@") ? normalized.split("@")[0] : normalized;
        const parts = emailPrefix
          .split(/[^a-zA-Z0-9]+/)
          .map((part) => part.trim())
          .filter(Boolean);

        if (parts.length === 0) {
          return emailPrefix.slice(0, 2).toUpperCase();
        }

        if (parts.length === 1) {
          return parts[0].slice(0, 2).toUpperCase();
        }

        return (parts[0][0] + parts[1][0]).toUpperCase();
      }

      function formatEmailPrefixDisplayName(value) {
        const normalizedValue = String(value || "").trim();
        if (!normalizedValue) {
          return "";
        }

        const emailPrefix = normalizedValue.includes("@") ? normalizedValue.split("@")[0] : normalizedValue;
        const parts = emailPrefix
          .split(/[^a-zA-Z0-9]+/)
          .map((part) => part.trim())
          .filter(Boolean);

        if (parts.length === 0) {
          return emailPrefix;
        }

        return parts
          .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
          .join(" ");
      }

      function getTrustedDisplayName(displayName, email) {
        const normalizedDisplayName = String(displayName || "").replace(/\\s+/g, " ").trim();
        if (!normalizedDisplayName) {
          return "";
        }

        const derivedEmailName = formatEmailPrefixDisplayName(email);
        if (
          derivedEmailName
          && normalizedDisplayName.localeCompare(derivedEmailName, undefined, { sensitivity: "accent" }) === 0
        ) {
          return "";
        }

        return normalizedDisplayName;
      }

      function formatAccountDisplayName(displayName, email, fallbackValue) {
        const trustedDisplayName = getTrustedDisplayName(displayName, email);
        if (trustedDisplayName) {
          return trustedDisplayName;
        }

        const emailDerivedDisplayName = formatEmailPrefixDisplayName(email);
        if (emailDerivedDisplayName) {
          return emailDerivedDisplayName;
        }

        const normalizedFallback = String(fallbackValue || "").trim();
        if (normalizedFallback) {
          return normalizedFallback;
        }

        return "Computer Agents";
      }

      function getWelcomeGreetingName(displayName, email) {
        const trustedDisplayName = getTrustedDisplayName(displayName, email);
        const preferredSource = trustedDisplayName || formatEmailPrefixDisplayName(email);
        const normalizedSource = String(preferredSource || "").replace(/\\s+/g, " ").trim();

        if (!normalizedSource) {
          return "there";
        }

        const firstSegment = normalizedSource.split(" ")[0] || normalizedSource;
        return firstSegment || "there";
      }

      function buildWelcomeGreeting(displayName, email) {
        const greetingName = getWelcomeGreetingName(displayName, email);
        const templateIndex = Math.floor(Math.random() * RUNNER_WELCOME_GREETING_TEMPLATES.length);
        return RUNNER_WELCOME_GREETING_TEMPLATES[templateIndex].replace("<name>", greetingName);
      }

      function formatSubscriptionTier(value) {
        switch (String(value || "").trim().toLowerCase()) {
          case "pro":
            return "Pro";
          case "scale":
            return "Scale";
          case "max":
            return "Max";
          case "free":
            return "Free";
          default:
            return "Free";
        }
      }

      function formatSettingsCurrency(value) {
        return new Intl.NumberFormat("en-US", {
          style: "currency",
          currency: "USD",
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        }).format(Number.isFinite(Number(value)) ? Number(value) : 0);
      }

      function settingsDollarsToComputeTokens(value) {
        const numericValue = Number(value);
        if (!Number.isFinite(numericValue)) {
          return 0;
        }

        return Math.max(0, Math.round(numericValue * SETTINGS_CT_PER_DOLLAR));
      }

      function clampSettingsPercentage(value) {
        const numericValue = Number(value);
        if (!Number.isFinite(numericValue)) {
          return 0;
        }

        return Math.max(0, Math.min(100, Math.round(numericValue)));
      }

      function readSettingsComputeTokens(record, ctKey, currencyKey) {
        if (record && record[ctKey] != null) {
          const ctValue = Number(record[ctKey]);
          if (Number.isFinite(ctValue)) {
            return Math.max(0, Math.round(ctValue));
          }
        }

        if (record && currencyKey && record[currencyKey] != null) {
          return settingsDollarsToComputeTokens(record[currencyKey]);
        }

        return 0;
      }

      function formatSettingsComputeTokens(value) {
        const numericValue = Math.max(0, Math.round(Number.isFinite(Number(value)) ? Number(value) : 0));
        if (numericValue >= 1000) {
          const compact = (numericValue / 1000).toFixed(numericValue >= 10000 ? 0 : 1).replace(".0", "");
          return compact + "k CT";
        }

        return numericValue + " CT";
      }

      function formatSettingsAxisComputeTokens(value) {
        return Math.max(0, Math.round(Number.isFinite(Number(value)) ? Number(value) : 0)).toLocaleString("en-US") + " CT";
      }

      function getSettingsSourceLabel(sourceId) {
        return SETTINGS_SOURCE_LABELS[sourceId] || sourceId;
      }

      function getSettingsSourceChannel(sourceId) {
        return SETTINGS_SOURCE_CHANNELS[sourceId] || "integrations";
      }

      function getSettingsPlanFeatures(tierId, computeTokens) {
        const usageIcon = SETTINGS_TIER_USAGE_ICONS[tierId] || Coins;
        const usageMultiplier = Math.round(computeTokens / 150);
        const usageText = tierId === "free"
          ? computeTokens + " Compute Tokens included"
          : usageMultiplier + "x Usage (" + (computeTokens >= 1000
            ? String((computeTokens / 1000).toFixed(1)).replace(".0", "") + "k"
            : computeTokens) + " CT)";
        const isPaidTier = tierId !== "free";
        const features = [
          { text: usageText, icon: usageIcon },
        ];

        if (isPaidTier) {
          features.push({ text: "Access to premium models", icon: Telescope });
          features.push({ text: "Create your own Agents", icon: User });
        }

        features.push(
          { text: "Create your own Environments", icon: Cloud },
          { text: "Work with any documents", icon: FileText },
          { text: "Integrate with all your apps", icon: Cable },
          { text: "Best-in-class Research models", icon: Telescope },
          { text: "Best-in-class image models", icon: ImageIcon },
          { text: "Schedule Tasks", icon: Clock },
          { text: "API Access", icon: Code }
        );

        if (tierId === "max") {
          features.push({ text: "Run on your own hardware", icon: HardDrive });
        }

        return features;
      }

      function getSettingsTierLogoUrl(value) {
        const tierId = String(value || "").trim().toLowerCase();
        if (tierId === "pro" || tierId === "scale" || tierId === "max") {
          return "/img/logos/" + tierId + "icon.png";
        }

        return "/img/logos/settingsicon.png";
      }

      function formatSettingsBillingReason(value) {
        const normalized = String(value || "").trim();
        if (!normalized) {
          return "";
        }

        return normalized.replace(/_/g, " ");
      }

      function createEmptySettingsUsageSummary() {
        return {
          startDate: "",
          endDate: "",
          totals: {
            totalCT: 0,
            agentCT: 0,
            environmentCT: 0,
            totalThreads: 0,
          },
          byDay: [],
        };
      }

      function formatSettingsDate(value) {
        if (!value) {
          return "Unavailable";
        }

        const date = new Date(value);
        if (Number.isNaN(date.getTime())) {
          return "Unavailable";
        }

        return date.toLocaleDateString("en-US", {
          month: "short",
          day: "numeric",
          year: "numeric",
        });
      }

      function formatSettingsDateTime(value) {
        if (!value) {
          return "Unavailable";
        }

        const date = new Date(value);
        if (Number.isNaN(date.getTime())) {
          return "Unavailable";
        }

        return date.toLocaleString("en-US", {
          month: "short",
          day: "numeric",
          year: "numeric",
          hour: "numeric",
          minute: "2-digit",
        });
      }

      function getSettingsApiKeyScopeLabel(permissions) {
        const items = Array.isArray(permissions) ? permissions : [];
        for (const preset of Object.values(SETTINGS_API_KEY_SCOPE_PRESETS)) {
          if (
            preset.permissions.length === items.length &&
            preset.permissions.every((permission) => items.includes(permission))
          ) {
            return preset.label;
          }
        }
        return items.length ? "Custom" : "Default";
      }

      function isSettingsSystemManagedKey(apiKeyRecord) {
        const metadata = apiKeyRecord?.metadata && typeof apiKeyRecord.metadata === "object" && !Array.isArray(apiKeyRecord.metadata)
          ? apiKeyRecord.metadata
          : {};
        return metadata.isDefault === true || typeof metadata.createdBy === "string" && metadata.createdBy.includes("provisioner");
      }

      function getSettingsTriggerSourceMeta(source) {
        switch (String(source || "").trim().toLowerCase()) {
          case "github":
            return {
              label: "GitHub",
              icon: GitCommitHorizontal,
            };
          case "slack":
            return {
              label: "Slack",
              icon: MessageCircle,
            };
          default:
            return {
              label: "Webhook",
              icon: Webhook,
            };
        }
      }

      function mapFirebaseAuthErrorMessage(code, fallbackMessage) {
        const normalized = String(code || "").trim().toUpperCase();
        if (!normalized) {
          return fallbackMessage;
        }
        if (normalized === "INVALID_LOGIN_CREDENTIALS" || normalized === "INVALID_PASSWORD") {
          return "Current password is incorrect.";
        }
        if (normalized === "EMAIL_NOT_FOUND" || normalized === "USER_NOT_FOUND") {
          return "This account could not be verified.";
        }
        if (normalized.startsWith("WEAK_PASSWORD")) {
          return "New password must be at least 6 characters.";
        }
        if (normalized === "USER_DISABLED") {
          return "This account is disabled.";
        }
        if (normalized === "TOO_MANY_ATTEMPTS_TRY_LATER") {
          return "Too many attempts. Try again later.";
        }
        if (normalized === "OPERATION_NOT_ALLOWED") {
          return "Password authentication is not enabled for this account.";
        }
        return fallbackMessage;
      }

      function buildFirebaseRestUrl(pathname) {
        return "https://identitytoolkit.googleapis.com/v1/" + pathname + "?key=" + encodeURIComponent(FIREBASE_WEB_API_KEY);
      }

      function normalizeSessionIdentityValue(value) {
        return String(value || "").replace(/\\s+/g, " ").trim();
      }

      function getSessionIdentityObject(value) {
        return value && typeof value === "object" && !Array.isArray(value) ? value : null;
      }

      function pickFirstSessionIdentityValue(...values) {
        for (const value of values) {
          const normalizedValue = normalizeSessionIdentityValue(value);
          if (normalizedValue) {
            return normalizedValue;
          }
        }
        return "";
      }

      function normalizeSessionPhotoUrl(value) {
        const normalizedValue = normalizeSessionIdentityValue(value);
        if (!normalizedValue) {
          return "";
        }
        if (normalizedValue.startsWith("//")) {
          return "https:" + normalizedValue;
        }
        return normalizedValue;
      }

      function getPreferredSessionProviderProfile(...sources) {
        const providerEntries = [];
        sources.forEach((source) => {
          const providerUserInfo = Array.isArray(source?.providerUserInfo) ? source.providerUserInfo : [];
          providerUserInfo.forEach((entry) => {
            const normalizedEntry = getSessionIdentityObject(entry);
            if (normalizedEntry) {
              providerEntries.push(normalizedEntry);
            }
          });
        });

        if (!providerEntries.length) {
          return null;
        }

        return (
          providerEntries.find((entry) => normalizeSessionIdentityValue(entry.providerId).toLowerCase() === "google.com")
          || providerEntries.find((entry) => (
            pickFirstSessionIdentityValue(
              entry.displayName,
              entry.name,
              entry.email,
              entry.photoUrl,
              entry.photoURL,
              entry.avatarUrl,
              entry.picture
            )
          ))
          || null
        );
      }

      function extractSessionIdentityFromPayload(payload) {
        const root = getSessionIdentityObject(payload);
        const profile = getSessionIdentityObject(root?.profile);
        const user = getSessionIdentityObject(root?.user);
        const authProfile = getSessionIdentityObject(root?.authProfile);
        const preferredProvider = getPreferredSessionProviderProfile(root, profile, user, authProfile);

        const email = pickFirstSessionIdentityValue(
          root?.email,
          profile?.email,
          user?.email,
          authProfile?.email,
          preferredProvider?.email
        );
        const displayName = getTrustedDisplayName(
          pickFirstSessionIdentityValue(
            profile?.displayName,
            profile?.display_name,
            profile?.name,
            root?.displayName,
            root?.display_name,
            root?.name,
            user?.displayName,
            user?.display_name,
            user?.name,
            authProfile?.displayName,
            authProfile?.display_name,
            authProfile?.name,
            preferredProvider?.displayName,
            preferredProvider?.name
          ),
          email
        ) || formatEmailPrefixDisplayName(email);
        const photoURL = normalizeSessionPhotoUrl(
          pickFirstSessionIdentityValue(
            profile?.photoURL,
            profile?.photoUrl,
            profile?.photo_url,
            profile?.avatarUrl,
            profile?.avatarURL,
            profile?.avatar,
            profile?.picture,
            root?.photoURL,
            root?.photoUrl,
            root?.photo_url,
            root?.avatarUrl,
            root?.avatar,
            root?.picture,
            user?.photoURL,
            user?.photoUrl,
            user?.photo_url,
            user?.avatarUrl,
            user?.avatar,
            user?.picture,
            authProfile?.photoURL,
            authProfile?.photoUrl,
            authProfile?.photo_url,
            authProfile?.avatarUrl,
            authProfile?.avatar,
            authProfile?.picture,
            preferredProvider?.photoURL,
            preferredProvider?.photoUrl,
            preferredProvider?.photo_url,
            preferredProvider?.avatarUrl,
            preferredProvider?.avatar,
            preferredProvider?.picture
          )
        );
        const emailVerified = typeof root?.emailVerified === "boolean"
          ? root.emailVerified
          : (typeof authProfile?.emailVerified === "boolean" ? authProfile.emailVerified : undefined);

        return {
          email,
          displayName,
          photoURL: canRenderAvatarImage(photoURL) ? photoURL : "",
          emailVerified,
        };
      }

      function readNamedCookie(name) {
        if (typeof document === "undefined") {
          return "";
        }
        const normalizedName = String(name || "").trim();
        if (!normalizedName) {
          return "";
        }
        const escapedName = normalizedName.replace(/[.*+?^{}$()|[\\]\\\\]/g, "\\\\$&");
        const match = document.cookie.match(new RegExp("(?:^|; )" + escapedName + "=([^;]*)"));
        if (!match || typeof match[1] !== "string") {
          return "";
        }
        try {
          return decodeURIComponent(match[1]);
        } catch {
          return match[1];
        }
      }

      async function lookupFirebaseSessionIdentity() {
        const sessionToken = readNamedCookie("__session");
        if (!sessionToken) {
          return null;
        }

        const response = await fetch(buildFirebaseRestUrl("accounts:lookup"), {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            idToken: sessionToken,
          }),
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok) {
          return null;
        }

        const user = Array.isArray(data?.users) ? getSessionIdentityObject(data.users[0]) : null;
        if (!user) {
          return null;
        }

        return extractSessionIdentityFromPayload({
          email: user.email,
          emailVerified: user.emailVerified,
          user: {
            email: user.email,
            displayName: user.displayName,
            name: user.displayName,
            photoURL: user.photoURL || user.photoUrl,
            photoUrl: user.photoUrl || user.photoURL,
            providerUserInfo: Array.isArray(user.providerUserInfo) ? user.providerUserInfo : [],
          },
        });
      }

      async function copyTextToClipboard(value) {
        try {
          await navigator.clipboard.writeText(String(value || ""));
          return true;
        } catch {
          return false;
        }
      }

      function canRenderAvatarImage(value) {
        const normalized = normalizeSessionPhotoUrl(value);
        return normalized.startsWith("data:image/") || /^https?:\/\//i.test(normalized);
      }

      function AccountAvatar({ className, imageClassName, fallbackLabel, photoUrl }) {
        const [imageFailed, setImageFailed] = useState(false);
        const normalizedPhotoUrl = normalizeSessionPhotoUrl(photoUrl);
        const normalizedFallbackLabel = normalizeSessionIdentityValue(fallbackLabel) || "CA";

        useEffect(() => {
          setImageFailed(false);
        }, [normalizedPhotoUrl]);

        return React.createElement("div", { className },
          !imageFailed && canRenderAvatarImage(normalizedPhotoUrl)
            ? React.createElement("img", {
                className: imageClassName,
                src: normalizedPhotoUrl,
                alt: normalizedFallbackLabel,
                referrerPolicy: "no-referrer",
                onError: () => setImageFailed(true),
              })
            : normalizedFallbackLabel
        );
      }

      function readFileAsDataUrl(file) {
        return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(typeof reader.result === "string" ? reader.result : "");
          reader.onerror = () => reject(reader.error || new Error("Failed to read file"));
          reader.readAsDataURL(file);
        });
      }

      async function readFileAsBase64(file) {
        const dataUrl = await readFileAsDataUrl(file);
        const commaIndex = dataUrl.indexOf(",");
        return commaIndex >= 0 ? dataUrl.slice(commaIndex + 1) : dataUrl;
      }

      function loadImageElement(src) {
        return new Promise((resolve, reject) => {
          const image = new Image();
          image.onload = () => resolve(image);
          image.onerror = () => reject(new Error("Failed to load selected image"));
          image.src = src;
        });
      }

      async function createProfilePhotoDataUrl(file) {
        const sourceDataUrl = await readFileAsDataUrl(file);
        const image = await loadImageElement(sourceDataUrl);
        const canvas = document.createElement("canvas");
        const targetSize = 320;
        const sourceWidth = image.naturalWidth || image.width || targetSize;
        const sourceHeight = image.naturalHeight || image.height || targetSize;
        const squareSize = Math.min(sourceWidth, sourceHeight);
        const sourceX = Math.max(0, Math.floor((sourceWidth - squareSize) / 2));
        const sourceY = Math.max(0, Math.floor((sourceHeight - squareSize) / 2));

        canvas.width = targetSize;
        canvas.height = targetSize;

        const context = canvas.getContext("2d");
        if (!context) {
          throw new Error("Failed to prepare profile picture preview");
        }

        context.clearRect(0, 0, targetSize, targetSize);
        context.drawImage(
          image,
          sourceX,
          sourceY,
          squareSize,
          squareSize,
          0,
          0,
          targetSize,
          targetSize
        );

        return canvas.toDataURL("image/jpeg", 0.84);
      }

