        const [loadingAgentId, setLoadingAgentId] = useState("");
        const [agentListMode, setAgentListMode] = useState(() => {
          const initialSelectedAgent = agents.find((agent) => agent?.id === initialAgentId) || null;
          return getPlaygroundAgentListMode(initialSelectedAgent);
        });
        const [saveState, setSaveState] = useState({
          isSaving: false,
          error: "",
          message: "",
        });
        const [isAgentDescriptionEditing, setIsAgentDescriptionEditing] = useState(false);
        const [isAgentInstructionsEditing, setIsAgentInstructionsEditing] = useState(false);
        const [agentDetailsCollapsed, setAgentDetailsCollapsed] = useState(false);
        const [agentActionsPopoverOpen, setAgentActionsPopoverOpen] = useState(false);
        const [agentRenameState, setAgentRenameState] = useState(null);
        const [agentRenameValue, setAgentRenameValue] = useState("");
        const [agentRenameError, setAgentRenameError] = useState("");
        const [agentModelPopover, setAgentModelPopover] = useState("");
        const [expandedSections, setExpandedSections] = useState(() => new Set(["team", "model", "instructions"]));

        const orderedAgents = useMemo(() => {
          return [...agents].sort((left, right) => {
            if (Boolean(left?.isDefault) !== Boolean(right?.isDefault)) {
              return left?.isDefault ? -1 : 1;
            }
            if (Boolean(left?.isSystem) !== Boolean(right?.isSystem)) {
              return left?.isSystem ? -1 : 1;
            }
            return String(left?.name || "").localeCompare(String(right?.name || ""));
          });
        }, [agents]);

        const allKnownAgents = useMemo(() => {
          const next = {};
          orderedAgents.forEach((agent) => {
            if (!agent?.id) return;
            next[agent.id] = normalizePlaygroundAgentRecord({
              ...(next[agent.id] || {}),
              ...agent,
            });
          });
          Object.values(agentDetailsById).forEach((agent) => {
            if (!agent?.id) return;
            next[agent.id] = normalizePlaygroundAgentRecord({
              ...(next[agent.id] || {}),
              ...agent,
            });
          });
          return Object.values(next);
        }, [agentDetailsById, orderedAgents]);

        const availableTeamMemberAgents = useMemo(() => {
          return allKnownAgents.filter((agent) => {
            if (!agent?.id || agent.id === PLAYGROUND_AGENT_DRAFT_ID) {
              return false;
            }
            if (draftAgent?.id && draftAgent.id !== PLAYGROUND_AGENT_DRAFT_ID && agent.id === draftAgent.id) {
              return false;
            }
            return !isPlaygroundTeamAgent(agent);
          });
        }, [allKnownAgents, draftAgent?.id]);

        const availableTeamMemberAgentsById = useMemo(() => {
          const next = {};
          availableTeamMemberAgents.forEach((agent) => {
            if (!agent?.id) return;
            next[agent.id] = agent;
          });
          return next;
        }, [availableTeamMemberAgents]);

        const selectedAgentSnapshot = useMemo(() => {
          if (!selectedAgentId || selectedAgentId === PLAYGROUND_AGENT_DRAFT_ID) {
            return null;
          }
          return agentDetailsById[selectedAgentId]
            || orderedAgents.find((agent) => agent.id === selectedAgentId)
            || null;
        }, [agentDetailsById, orderedAgents, selectedAgentId]);

        const filteredOrderedAgents = useMemo(() => {
          return orderedAgents.filter((agent) => getPlaygroundAgentListMode(agent) === agentListMode);
        }, [agentListMode, orderedAgents]);

        const selectedAgentListPreview = useMemo(() => {
          if (selectedAgentId === PLAYGROUND_AGENT_DRAFT_ID) {
            return draftAgent
              ? {
                  ...draftAgent,
                  id: PLAYGROUND_AGENT_DRAFT_ID,
                }
              : null;
          }
          if (draftAgent?.id && draftAgent.id === selectedAgentId) {
            return draftAgent;
          }
          return selectedAgentSnapshot;
        }, [draftAgent, selectedAgentId, selectedAgentSnapshot]);

        const selectedAgentListPreviewMode = selectedAgentListPreview ? getPlaygroundAgentListMode(selectedAgentListPreview) : "agents";

        const displayAgents = useMemo(() => {
          const items = [...filteredOrderedAgents];
          if (!selectedAgentListPreview || selectedAgentListPreviewMode !== agentListMode) {
            return items;
          }

          const previewIndex = items.findIndex((agent) => agent.id === selectedAgentListPreview.id);
          if (previewIndex >= 0) {
            items[previewIndex] = normalizePlaygroundAgentRecord({
              ...items[previewIndex],
              ...selectedAgentListPreview,
            });
          } else {
            items.unshift(selectedAgentListPreview);
          }

          return items;
        }, [agentListMode, filteredOrderedAgents, selectedAgentListPreview, selectedAgentListPreviewMode]);

        const searchResults = useMemo(() => {
          const query = searchPopupQuery.trim().toLowerCase();
          if (!query) return [];
          return displayAgents
            .filter((agent) => {
              const haystack = [agent?.name || "", agent?.description || "", agent?.instructions || ""].join(" ").toLowerCase();
              return haystack.includes(query);
            })
            .slice(0, 12);
        }, [displayAgents, searchPopupQuery]);

        const isLoadingCurrentAgent = Boolean(
          selectedAgentId
          && selectedAgentId !== PLAYGROUND_AGENT_DRAFT_ID
          && loadingAgentId === selectedAgentId
        );
        const isSystemAgent = Boolean(draftAgent?.isSystem);

        function resetEditorAuxiliaryState() {
          editorDirtyRef.current = false;
          setIsAgentDescriptionEditing(false);
          setIsAgentInstructionsEditing(false);
          setAgentActionsPopoverOpen(false);
          setAgentModelPopover("");
          setSaveState({
            isSaving: false,
            error: "",
            message: "",
          });
        }

        function resizeAgentDescriptionTextarea(textarea) {
          if (!textarea) return;
          const computedStyles = window.getComputedStyle(textarea);
          const lineHeight = Number.parseFloat(computedStyles.lineHeight) || 21;
          const paddingTop = Number.parseFloat(computedStyles.paddingTop) || 0;
          const paddingBottom = Number.parseFloat(computedStyles.paddingBottom) || 0;
          const borderTopWidth = Number.parseFloat(computedStyles.borderTopWidth) || 0;
          const borderBottomWidth = Number.parseFloat(computedStyles.borderBottomWidth) || 0;
          const singleLineHeight = Math.ceil(lineHeight + paddingTop + paddingBottom + borderTopWidth + borderBottomWidth);
          textarea.style.height = "auto";
          const nextHeight = String(textarea.value || "").trim()
            ? Math.max(singleLineHeight, textarea.scrollHeight)
            : singleLineHeight;
          textarea.style.height = nextHeight + "px";
        }

        function applyAgentMarkdownSelection(field, textareaRef, nextValue, nextSelectionStart, nextSelectionEnd = nextSelectionStart) {
          updateAgentField(field, nextValue);
          window.requestAnimationFrame(() => {
            const textarea = textareaRef.current;
            if (!textarea) {
              return;
            }
            const maxLength = nextValue.length;
            const safeSelectionStart = Math.max(0, Math.min(nextSelectionStart, maxLength));
            const safeSelectionEnd = Math.max(safeSelectionStart, Math.min(nextSelectionEnd, maxLength));
            textarea.focus();
            textarea.setSelectionRange(safeSelectionStart, safeSelectionEnd);
            resizeAgentDescriptionTextarea(textarea);
          });
        }

        function buildWrappedAgentMarkdownEdit(value, selectionStart, selectionEnd, prefix, suffix = prefix) {
          const safeStart = Math.max(0, selectionStart);
          const safeEnd = Math.max(safeStart, selectionEnd);
          const selectedText = value.slice(safeStart, safeEnd);
          if (safeStart !== safeEnd) {
            if (
              selectedText.startsWith(prefix)
              && selectedText.endsWith(suffix)
              && selectedText.length >= prefix.length + suffix.length
            ) {
              const unwrappedText = selectedText.slice(prefix.length, selectedText.length - suffix.length);
              const nextValue = value.slice(0, safeStart) + unwrappedText + value.slice(safeEnd);
              return {
                value: nextValue,
                selectionStart: safeStart,
                selectionEnd: safeStart + unwrappedText.length,
              };
            }

            const surroundingPrefix = value.slice(Math.max(0, safeStart - prefix.length), safeStart);
            const surroundingSuffix = value.slice(safeEnd, safeEnd + suffix.length);
            if (surroundingPrefix === prefix && surroundingSuffix === suffix) {
              const nextValue =
                value.slice(0, safeStart - prefix.length)
                + selectedText
                + value.slice(safeEnd + suffix.length);
              return {
                value: nextValue,
                selectionStart: safeStart - prefix.length,
                selectionEnd: safeStart - prefix.length + selectedText.length,
              };
            }

            const wrappedText = prefix + selectedText + suffix;
            const nextValue = value.slice(0, safeStart) + wrappedText + value.slice(safeEnd);
            return {
              value: nextValue,
              selectionStart: safeStart + prefix.length,
              selectionEnd: safeStart + prefix.length + selectedText.length,
            };
          }

          const insertedText = prefix + suffix;
          const nextValue = value.slice(0, safeStart) + insertedText + value.slice(safeEnd);
          return {
            value: nextValue,
            selectionStart: safeStart + prefix.length,
            selectionEnd: safeStart + prefix.length,
          };
        }

        function buildAgentMarkdownListEdit(value, selectionStart, selectionEnd) {
          const safeStart = Math.max(0, selectionStart);
          const safeEnd = Math.max(safeStart, selectionEnd);
          const lineStart = value.lastIndexOf("\\n", Math.max(0, safeStart - 1)) + 1;
          let lineEnd = value.indexOf("\\n", safeEnd);
          if (lineEnd === -1) {
            lineEnd = value.length;
          }
          const block = value.slice(lineStart, lineEnd);
          const lines = block.split("\\n");
          const nonEmptyLines = lines.filter((line) => line.trim().length > 0);
          const shouldRemoveList = nonEmptyLines.length > 0 && nonEmptyLines.every((line) => /^(\\s*)-\\s+/.test(line));
          const nextLines = lines.map((line) => {
            if (!line.trim()) {
              return shouldRemoveList ? line : "- ";
            }
            if (shouldRemoveList) {
              return line.replace(/^(\\s*)-\\s+/, "$1");
            }
            if (/^(\\s*)-\\s+/.test(line)) {
              return line;
            }
            return line.replace(/^(\\s*)/, "$1- ");
          });
          const nextBlock = nextLines.join("\\n");
          const nextValue = value.slice(0, lineStart) + nextBlock + value.slice(lineEnd);
          const collapsedSelection = safeStart === safeEnd;
          const nextCaretOffset = shouldRemoveList
            ? Math.max(0, safeStart - lineStart - 2)
            : safeStart - lineStart + 2;
          return {
            value: nextValue,
            selectionStart: collapsedSelection ? lineStart + Math.max(0, nextCaretOffset) : lineStart,
            selectionEnd: collapsedSelection ? lineStart + Math.max(0, nextCaretOffset) : lineStart + nextBlock.length,
          };
        }

        function handleAgentMarkdownFormat(field, textareaRef, formatType) {
          const textarea = textareaRef.current;
          if (!textarea || !draftAgent || isSystemAgent) {
            return;
          }
          const value = String(draftAgent?.[field] || "");
          const selectionStart = typeof textarea.selectionStart === "number" ? textarea.selectionStart : value.length;
          const selectionEnd = typeof textarea.selectionEnd === "number" ? textarea.selectionEnd : selectionStart;
          let edit = null;

          if (formatType === "bold") {
            edit = buildWrappedAgentMarkdownEdit(value, selectionStart, selectionEnd, "**");
          } else if (formatType === "italic") {
            edit = buildWrappedAgentMarkdownEdit(value, selectionStart, selectionEnd, "*");
          } else if (formatType === "underline") {
            edit = buildWrappedAgentMarkdownEdit(value, selectionStart, selectionEnd, "++");
          } else if (formatType === "list") {
            edit = buildAgentMarkdownListEdit(value, selectionStart, selectionEnd);
          }

          if (!edit) {
            return;
          }

          applyAgentMarkdownSelection(field, textareaRef, edit.value, edit.selectionStart, edit.selectionEnd);
        }

        function updateDraftAgent(updater) {
          setDraftAgent((current) => {
            const base = current || normalizePlaygroundAgentRecord(selectedAgentSnapshot || buildPlaygroundDefaultAgentDraft());
            return typeof updater === "function" ? updater(base) : updater;
          });
          editorDirtyRef.current = true;
          setSaveState((current) => ({
            ...current,
            error: "",
            message: "",
          }));
        }

        function updateAgentField(field, value) {
          updateDraftAgent((current) => ({
            ...current,
            [field]: value,
          }));
        }

        function toggleToolbarPopover(nextValue) {
          setToolbarPopover((current) => current === nextValue ? "" : nextValue);
        }

        function toggleSection(sectionId) {
          setExpandedSections((current) => {
            const next = new Set(current);
            if (next.has(sectionId)) {
              next.delete(sectionId);
            } else {
              next.add(sectionId);
            }
            return next;
          });
        }

        function toggleSkill(skillId) {
          updateDraftAgent((current) => {
            const currentSkills = Array.isArray(current.enabledSkills) ? current.enabledSkills : [];
            const isEnabled = currentSkills.includes(skillId);
            const nextSkills = isEnabled
              ? currentSkills.filter((value) => value !== skillId)
              : currentSkills.concat(skillId);
            const nextAgent = {
              ...current,
              enabledSkills: nextSkills,
            };
            if (skillId === "deep_research" && isEnabled) {
              nextAgent.deepResearchModel = buildPlaygroundDefaultAgentDraft().deepResearchModel;
            }
            return nextAgent;
          });
        }

        function updateAgentType(nextType) {
          const normalizedType = nextType === "team" ? "team" : "single";
          if (selectedAgentId === PLAYGROUND_AGENT_DRAFT_ID) {
            setAgentListMode(normalizedType === "team" ? "teams" : "agents");
          }
          updateDraftAgent((current) => {
            return {
              ...current,
              agentType: normalizedType,
              teamExecutionMode: normalizedType === "team" ? PLAYGROUND_AGENT_TEAM_EXECUTION_MODE : "",
              teamOrchestratorAgentId: normalizedType === "team"
                ? String(current.teamOrchestratorAgentId || "").trim()
                : "",
              teamSubagentIds: normalizedType === "team"
                ? dedupePlaygroundAgentIds(current.teamSubagentIds)
                : [],
            };
          });
        }

        function updateTeamOrchestratorAgent(agentId) {
          updateDraftAgent((current) => {
            const normalizedId = String(agentId || "").trim();
            return {
              ...current,
              teamOrchestratorAgentId: normalizedId,
              teamSubagentIds: dedupePlaygroundAgentIds(current.teamSubagentIds).filter((value) => value !== normalizedId),
              model: availableTeamMemberAgentsById[normalizedId]?.model || current.model,
            };
          });
        }

        function toggleTeamSubagent(agentId) {
          updateDraftAgent((current) => {
            const normalizedId = String(agentId || "").trim();
            const orchestratorAgentId = String(current.teamOrchestratorAgentId || "").trim();
            if (!normalizedId || normalizedId === orchestratorAgentId) {
              return current;
            }

            const currentIds = dedupePlaygroundAgentIds(current.teamSubagentIds).filter((value) => value !== orchestratorAgentId);
            const nextIds = currentIds.includes(normalizedId)
              ? currentIds.filter((value) => value !== normalizedId)
              : currentIds.concat(normalizedId);

            return {
              ...current,
              teamSubagentIds: nextIds,
            };
          });
        }

        const loadAgentDetails = useCallback(async (agentId) => {
          if (!agentId || agentId === PLAYGROUND_AGENT_DRAFT_ID) {
            return;
          }

          setLoadingAgentId(agentId);
          try {
            const response = await fetch(backendUrl + "/agents/" + encodeURIComponent(agentId), {
              method: "GET",
              headers: requestHeaders,
            });
            const data = await response.json().catch(() => ({}));
            if (!response.ok) {
              throw new Error(data?.message || data?.error || "Failed to load agent.");
            }

            const normalized = getPlaygroundAgentResponseRecord(data);
            if (!normalized) {
              throw new Error("Agent response was empty.");
            }

            setAgentDetailsById((current) => ({
              ...current,
              [agentId]: normalized,
            }));
            if (selectedAgentId === agentId && !editorDirtyRef.current) {
              setDraftAgent(normalized);
            }
          } catch (error) {
            if (selectedAgentId === agentId) {
              setSaveState((current) => ({
                ...current,
                error: error instanceof Error ? error.message : "Failed to load agent.",
              }));
            }
          } finally {
            setLoadingAgentId((current) => current === agentId ? "" : current);
          }
        }, [backendUrl, requestHeaders, selectedAgentId]);

        useEffect(() => {
          setAgentDetailsById((current) => {
            const next = {};
            agents.forEach((agent) => {
              if (!agent?.id) return;
              next[agent.id] = normalizePlaygroundAgentRecord({
                ...(current[agent.id] || {}),
                ...agent,
              });
            });
            return next;
          });
        }, [agents]);

        useEffect(() => {
          if (selectedAgentId === PLAYGROUND_AGENT_DRAFT_ID && selectedAgentListPreviewMode === agentListMode) {
            return;
          }
          if (selectedAgentId && selectedAgentId !== PLAYGROUND_AGENT_DRAFT_ID && filteredOrderedAgents.some((agent) => agent.id === selectedAgentId)) {
            return;
          }
          if (selectedAgentId && selectedAgentId !== PLAYGROUND_AGENT_DRAFT_ID && selectedAgentListPreview && selectedAgentListPreviewMode === agentListMode) {
            return;
          }
          const fallbackAgent = filteredOrderedAgents.find((agent) => agent.isDefault) || filteredOrderedAgents[0] || null;
          setSelectedAgentId(fallbackAgent?.id || "");
        }, [agentListMode, filteredOrderedAgents, selectedAgentId, selectedAgentListPreview, selectedAgentListPreviewMode]);

        useEffect(() => {
          if (!toolbarPopover) return;

          const focusFrame = toolbarPopover === "search"
            ? window.requestAnimationFrame(() => {
                if (searchPopupInputRef.current) {
                  searchPopupInputRef.current.focus();
                  searchPopupInputRef.current.select();
                }
              })
            : 0;

          function handleKeyDown(event) {
            if (event.key === "Escape") {
              setToolbarPopover("");
            }
          }

          window.addEventListener("keydown", handleKeyDown);
          return () => {
            if (focusFrame) {
              window.cancelAnimationFrame(focusFrame);
            }
            window.removeEventListener("keydown", handleKeyDown);
          };
        }, [toolbarPopover]);

        useEffect(() => {
          if (!selectedAgentId || selectedAgentId === PLAYGROUND_AGENT_DRAFT_ID) {
            if (selectedAgentId !== PLAYGROUND_AGENT_DRAFT_ID) {
              setDraftAgent(null);
              resetEditorAuxiliaryState();
            }
            return;
          }

          const seedAgent = agentDetailsById[selectedAgentId]
            || orderedAgents.find((agent) => agent.id === selectedAgentId)
            || null;

          resetEditorAuxiliaryState();
          setAgentDetailsCollapsed(false);
          setDraftAgent(seedAgent ? normalizePlaygroundAgentRecord(seedAgent) : null);
          void loadAgentDetails(selectedAgentId);
        }, [loadAgentDetails, orderedAgents, selectedAgentId]);

        useEffect(() => {
          if (!agentActionsPopoverOpen) {
            return undefined;
          }

          function handleAgentActionsPopoverPointerDown(event) {
            const target = event?.target instanceof Node ? event.target : null;
            if (!target || !agentActionsPopoverRef.current || agentActionsPopoverRef.current.contains(target)) {
              return;
            }
            setAgentActionsPopoverOpen(false);
          }

          function handleAgentActionsPopoverEscape(event) {
            if (event.key === "Escape") {
              setAgentActionsPopoverOpen(false);
            }
          }

          document.addEventListener("mousedown", handleAgentActionsPopoverPointerDown);
          window.addEventListener("keydown", handleAgentActionsPopoverEscape);
          return () => {
            document.removeEventListener("mousedown", handleAgentActionsPopoverPointerDown);
            window.removeEventListener("keydown", handleAgentActionsPopoverEscape);
          };
        }, [agentActionsPopoverOpen]);

        useEffect(() => {
          if (!agentRenameState || !agentRenameInputRef.current) {
            return undefined;
          }

          const focusFrame = window.requestAnimationFrame(() => {
            agentRenameInputRef.current?.focus();
            agentRenameInputRef.current?.select();
          });

          function handleAgentRenameEscape(event) {
            if (event.key === "Escape" && !saveState.isSaving) {
              event.preventDefault();
              closeAgentRenameDialog();
            }
          }

          window.addEventListener("keydown", handleAgentRenameEscape);
          return () => {
            window.cancelAnimationFrame(focusFrame);
            window.removeEventListener("keydown", handleAgentRenameEscape);
          };
        }, [agentRenameState, saveState.isSaving]);

        useLayoutEffect(() => {
          resizeAgentDescriptionTextarea(agentDescriptionTextareaRef.current);
        }, [draftAgent?.description, draftAgent?.id]);

        useLayoutEffect(() => {
          resizeAgentDescriptionTextarea(agentInstructionsTextareaRef.current);
        }, [draftAgent?.instructions, draftAgent?.id]);

        useEffect(() => {
          const textarea = agentDescriptionTextareaRef.current;
          const detailMain = agentDetailMainRef.current;
          if (!textarea || !detailMain) return undefined;

          let frameId = 0;
          const timeoutIds = [];
          const scheduleResize = () => {
            if (frameId) {
              window.cancelAnimationFrame(frameId);
            }
            frameId = window.requestAnimationFrame(() => {
              resizeAgentDescriptionTextarea(agentDescriptionTextareaRef.current);
              resizeAgentDescriptionTextarea(agentInstructionsTextareaRef.current);
            });
          };

          scheduleResize();
          [120, 240, 360].forEach((delay) => {
            timeoutIds.push(window.setTimeout(scheduleResize, delay));
          });

          if (typeof ResizeObserver === "undefined") {
            window.addEventListener("resize", scheduleResize);
            return () => {
              if (frameId) {
                window.cancelAnimationFrame(frameId);
              }
              timeoutIds.forEach((timeoutId) => window.clearTimeout(timeoutId));
              window.removeEventListener("resize", scheduleResize);
            };
          }

          const observer = new ResizeObserver(() => {
            scheduleResize();
          });
          observer.observe(detailMain);

          return () => {
            if (frameId) {
              window.cancelAnimationFrame(frameId);
            }
            timeoutIds.forEach((timeoutId) => window.clearTimeout(timeoutId));
            observer.disconnect();
          };
        }, [draftAgent?.id]);

        function handleAgentSelect(agentId) {
          setToolbarPopover("");
          setSearchPopupQuery("");
          setSelectedAgentId(agentId);
        }

        function handleAgentListModeChange(nextMode) {
          setToolbarPopover("");
          setSearchPopupQuery("");
          setAgentListMode(nextMode === "teams" ? "teams" : "agents");
        }

        function handleCreateAgent() {
          resetEditorAuxiliaryState();
          setToolbarPopover("");
          setSearchPopupQuery("");
          setAgentListMode("agents");
          setSelectedAgentId(PLAYGROUND_AGENT_DRAFT_ID);
          setDraftAgent(buildPlaygroundDefaultAgentDraft());
        }

        function handleCreateTeam() {
          resetEditorAuxiliaryState();
          setToolbarPopover("");
          setSearchPopupQuery("");
          setAgentListMode("teams");
          setSelectedAgentId(PLAYGROUND_AGENT_DRAFT_ID);
          setDraftAgent(buildPlaygroundDefaultAgentDraft("team"));
        }

        function closeAgentRenameDialog() {
          setAgentRenameState(null);
          setAgentRenameValue("");
          setAgentRenameError("");
        }

        function openAgentRenameDialog(agent) {
          if (!agent?.id || agent.id === PLAYGROUND_AGENT_DRAFT_ID || agent.isSystem) {
            return;
          }
          setAgentActionsPopoverOpen(false);
          setAgentRenameState({
            agentId: agent.id,
            originalName: String(agent.name || "").trim(),
          });
          setAgentRenameValue(String(agent.name || ""));
          setAgentRenameError("");
        }

        function buildPlaygroundAgentPersistedMetadata(agent) {
          const agentType = agent?.agentType === "team" ? "team" : "single";
          if (agentType !== "team") {
            const metadata = agent?.metadata && typeof agent.metadata === "object" && !Array.isArray(agent.metadata)
              ? agent.metadata
              : null;
            return getPlaygroundAgentTeamMetadata(metadata) ? null : metadata;
          }

          return {
            kind: "team",
            executionMode: PLAYGROUND_AGENT_TEAM_EXECUTION_MODE,
            team: {
              version: 1,
              orchestratorAgentId: String(agent?.teamOrchestratorAgentId || "").trim(),
              subagentIds: dedupePlaygroundAgentIds(agent?.teamSubagentIds).filter((value) => value !== String(agent?.teamOrchestratorAgentId || "").trim()),
            },
          };
        }

        function buildSanitizedAgentPayload(agent) {
          const metadata = buildPlaygroundAgentPersistedMetadata(agent);
          const isTeamAgent = agent?.agentType === "team";
          const orchestratorAgentId = metadata?.team?.orchestratorAgentId || "";
          const orchestratorAgent = orchestratorAgentId ? availableTeamMemberAgentsById[orchestratorAgentId] : null;

          return {
            name: String(agent?.name || "").trim() || (isTeamAgent ? "New Team" : "New Agent"),
            description: typeof agent?.description === "string" ? agent.description : "",
            model: getPlaygroundAgentModelMeta(
              typeof orchestratorAgent?.model === "string" && orchestratorAgent.model
                ? orchestratorAgent.model
                : typeof agent?.model === "string"
                  ? agent.model
                  : ""
            ).id,
            instructions: typeof agent?.instructions === "string" ? agent.instructions : "",
            binary: typeof orchestratorAgent?.binary === "string" && orchestratorAgent.binary.trim()
              ? orchestratorAgent.binary
              : typeof agent?.binary === "string" && agent.binary.trim()
                ? agent.binary
                : "Claude Code CLI",
            reasoningEffort: ["minimal", "low", "medium", "high"].includes(orchestratorAgent?.reasoningEffort)
              ? orchestratorAgent.reasoningEffort
              : ["minimal", "low", "medium", "high"].includes(agent?.reasoningEffort)
                ? agent.reasoningEffort
                : "medium",
            enabledSkills: isTeamAgent
              ? []
              : (Array.isArray(agent?.enabledSkills) ? agent.enabledSkills : []).map((value) => String(value || "").trim()).filter(Boolean),
            deepResearchModel: !isTeamAgent && PLAYGROUND_AGENT_DEEP_RESEARCH_MODEL_OPTIONS.some((option) => option.id === agent?.deepResearchModel)
              ? agent.deepResearchModel
              : null,
            metadata,
          };
        }

        async function persistAgentRecord(agentRecord) {
          if (!agentRecord) {
            throw new Error("Agent save failed.");
          }

          const payload = buildSanitizedAgentPayload(agentRecord);
          if (agentRecord.agentType === "team") {
            const orchestratorAgentId = String(payload?.metadata?.team?.orchestratorAgentId || "").trim();
            const subagentIds = Array.isArray(payload?.metadata?.team?.subagentIds)
              ? payload.metadata.team.subagentIds
              : [];

            if (!orchestratorAgentId) {
              throw new Error("Choose an orchestrator agent for the team.");
            }

            if (subagentIds.length === 0) {
              throw new Error("Select at least one fixed subagent for the team.");
            }
          }
          if (!payload.enabledSkills.includes("deep_research")) {
            payload.deepResearchModel = null;
          }

          const isCreating = agentRecord.id === PLAYGROUND_AGENT_DRAFT_ID || !agentRecord.id;
          const response = await fetch(
            isCreating
              ? backendUrl + "/agents"
              : backendUrl + "/agents/" + encodeURIComponent(agentRecord.id),
            {
              method: isCreating ? "POST" : "PATCH",
              headers: {
                ...requestHeaders,
                "Content-Type": "application/json",
              },
              body: JSON.stringify(payload),
            },
          );
          const data = await response.json().catch(() => ({}));
          if (!response.ok) {
            throw new Error(data?.message || data?.error || "Failed to save agent.");
          }

          const savedAgent = getPlaygroundAgentResponseRecord(data) || normalizePlaygroundAgentRecord({
            ...agentRecord,
            ...payload,
            updatedAt: new Date().toISOString(),
          });
          if (!savedAgent?.id) {
            throw new Error("Agent save failed.");
          }

          return savedAgent;
        }

        async function handleSaveAgent() {
          if (!draftAgent || isSystemAgent) {
            return;
          }

          setSaveState({
            isSaving: true,
            error: "",
            message: "",
          });

          try {
            const savedAgent = await persistAgentRecord(draftAgent);
            editorDirtyRef.current = false;
            setAgentDetailsById((current) => ({
              ...current,
              [savedAgent.id]: savedAgent,
            }));
            setAgentListMode(getPlaygroundAgentListMode(savedAgent));
            setSelectedAgentId(savedAgent.id);
            setDraftAgent(savedAgent);
            setSaveState({
              isSaving: false,
              error: "",
              message: "Saved",
            });
            if (onAgentMutated) {
              await onAgentMutated();
            }
          } catch (error) {
            setSaveState({
              isSaving: false,
              error: error instanceof Error ? error.message : "Failed to save agent.",
              message: "",
            });
          }
        }

        async function handleAgentRenameSubmit(event) {
          event.preventDefault();
          if (!agentRenameState?.agentId) {
            return;
          }

          const nextName = String(agentRenameValue || "").trim().replace(/\s+/g, " ");
          if (!nextName) {
            setAgentRenameError("Agent name cannot be empty.");
            return;
          }

          if (nextName === agentRenameState.originalName) {
            closeAgentRenameDialog();
            return;
          }

          const renameBaseAgent = normalizePlaygroundAgentRecord({
            ...(selectedAgentSnapshot || draftAgent || {}),
            id: agentRenameState.agentId,
            name: nextName,
          });

          setSaveState({
            isSaving: true,
            error: "",
            message: "",
          });
          setAgentRenameError("");

          try {
            const savedAgent = await persistAgentRecord(renameBaseAgent);
            setAgentDetailsById((current) => ({
              ...current,
              [savedAgent.id]: savedAgent,
            }));
            setSelectedAgentId(savedAgent.id);
            setDraftAgent((current) => current && current.id === savedAgent.id
              ? normalizePlaygroundAgentRecord({
                  ...current,
                  name: savedAgent.name,
                  updatedAt: savedAgent.updatedAt,
                  isDefault: savedAgent.isDefault,
                  isSystem: savedAgent.isSystem,
                })
              : savedAgent
            );
            setSaveState({
              isSaving: false,
              error: "",
              message: "Saved",
            });
            closeAgentRenameDialog();
            if (onAgentMutated) {
              await onAgentMutated();
            }
          } catch (error) {
            setAgentRenameError(error instanceof Error ? error.message : "Failed to rename agent.");
            setSaveState({
              isSaving: false,
              error: "",
              message: "",
            });
          }
        }

        async function handleDeleteAgent(agentId) {
          if (!agentId || agentId === PLAYGROUND_AGENT_DRAFT_ID) {
            handleCreateAgent();
            return;
          }

          if (!window.confirm("Delete this agent?")) {
            return;
          }

          setSaveState({
            isSaving: true,
            error: "",
            message: "",
          });

          try {
            const response = await fetch(backendUrl + "/agents/" + encodeURIComponent(agentId), {
              method: "DELETE",
              headers: requestHeaders,
            });
            const data = await response.json().catch(() => ({}));
            if (!response.ok) {
              throw new Error(data?.message || data?.error || "Failed to delete agent.");
            }

            setAgentDetailsById((current) => {
              const next = { ...current };
              delete next[agentId];
              return next;
            });
            setDraftAgent(null);
            setSaveState({
              isSaving: false,
              error: "",
              message: "",
            });
            if (selectedAgentId === agentId) {
              setSelectedAgentId("");
            }
            if (onAgentMutated) {
              await onAgentMutated();
            }
          } catch (error) {
            setSaveState({
              isSaving: false,
              error: error instanceof Error ? error.message : "Failed to delete agent.",
              message: "",
            });
          }
        }

        function handleRevertDraft() {
          if (selectedAgentId === PLAYGROUND_AGENT_DRAFT_ID) {
            setDraftAgent(buildPlaygroundDefaultAgentDraft(draftAgent?.agentType === "team" ? "team" : "single"));
            resetEditorAuxiliaryState();
            return;
          }
          const nextDraft = selectedAgentSnapshot ? normalizePlaygroundAgentRecord(selectedAgentSnapshot) : null;
          setDraftAgent(nextDraft);
          resetEditorAuxiliaryState();
        }

