        function commitLocalProjectRecord(projectRecord, extra = {}) {
          const normalized = normalizePlaygroundProjectRecord({
            ...projectRecord,
            summary: extra.summary && typeof extra.summary === "object"
              ? extra.summary
              : projectRecord?.summary,
          });

          setProjects((current) => {
            const existingIndex = current.findIndex((project) => project.id === normalized.id);
            if (existingIndex === -1) {
              return [normalized].concat(current);
            }
            return current.map((project) => project.id === normalized.id ? normalized : project);
          });

          if (typeof onProjectRecordCommitted === "function") {
            onProjectRecordCommitted(normalized);
          }

          if (selectedProjectId === normalized.id || extra.selectImmediately) {
            setSelectedProjectDetail((current) => ({
              project: normalized,
              summary: normalized.summary || current.summary || buildEmptyPlaygroundProjectSummary(),
              environments: Array.isArray(extra.environments) ? extra.environments : current.environments || [],
              recentThreads: Array.isArray(extra.recentThreads) ? extra.recentThreads : current.recentThreads || [],
            }));
          }

          return normalized;
        }

        function syncProjectSummary(projectId, nextTasks, nextSprints, nextReleases, summarySeed) {
          if (!projectId) return;
          const nextSummary = {
            ...buildEmptyPlaygroundProjectSummary(),
            ...(summarySeed && typeof summarySeed === "object" ? summarySeed : {}),
            tasksCount: nextTasks.length,
            openTasksCount: nextTasks.filter((task) => task.status !== "done").length,
            releaseCount: nextReleases.length,
            activeReleaseCount: nextReleases.filter((release) => getPlaygroundTaskReleaseStatus(release) === "active").length,
            sprintCount: nextSprints.length,
            activeSprintCount: nextSprints.filter((sprint) => sprint.status === "active").length,
          };

          setProjects((current) =>
            current.map((project) =>
              project.id === projectId
                ? {
                    ...project,
                    summary: {
                      ...buildEmptyPlaygroundProjectSummary(),
                      ...(project.summary && typeof project.summary === "object" ? project.summary : {}),
                      ...nextSummary,
                    },
                  }
                : project
            )
          );

          setSelectedProjectDetail((current) => {
            if (!current?.project || current.project.id !== projectId) {
              return current;
            }
            return {
              ...current,
              project: {
                ...current.project,
                summary: nextSummary,
              },
              summary: nextSummary,
            };
          });
        }

        async function loadProjectSchedules(projectId, visibleRange = visibleScheduleCalendarRange) {
          if (!projectId) {
            setSchedules([]);
            setScheduleLoadState({
              status: "idle",
              error: "",
            });
            return;
          }

          setScheduleLoadState((current) => ({
            status: "loading",
            error: current.status === "ready" ? "" : current.error,
          }));

          try {
            const requestTarget = new URL(backendUrl + "/projects/" + encodeURIComponent(projectId) + "/schedules", window.location.origin);
            if (visibleRange?.start instanceof Date && !Number.isNaN(visibleRange.start.getTime())) {
              requestTarget.searchParams.set("rangeStart", visibleRange.start.toISOString());
            }
            if (visibleRange?.end instanceof Date && !Number.isNaN(visibleRange.end.getTime())) {
              requestTarget.searchParams.set("rangeEnd", visibleRange.end.toISOString());
            }
            const response = await fetch(requestTarget.toString(), {
              method: "GET",
              headers: requestHeaders,
            });
            const data = await response.json().catch(() => ({}));
            if (!response.ok) {
              throw new Error(data?.message || data?.error || "Schedules API unavailable.");
            }
            setSchedules(parsePlaygroundScheduleListResponse(data));
            setScheduleLoadState({
              status: "ready",
              error: "",
            });
          } catch (error) {
            setScheduleLoadState({
              status: "error",
              error: error instanceof Error ? error.message : "Failed to load project schedules.",
            });
          }
        }

